import{_ as t,c as a,S as s,o as l}from"./chunks/framework.BjmDYXuv.js";const u=JSON.parse('{"title":"SFAPI Runner","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"internal/sfapi.md","filePath":"internal/sfapi.md","lastUpdated":1775814204000}'),i={name:"internal/sfapi.md"};function o(n,e,d,r,c,p){return l(),a("div",null,e[0]||(e[0]=[s(`<h1 id="sfapi-runner" tabindex="-1">SFAPI Runner <a class="header-anchor" href="#sfapi-runner" aria-label="Permalink to &quot;SFAPI Runner&quot;">​</a></h1><p>The backend dispatches simulation jobs to <strong>NERSC Perlmutter</strong> via the <a href="https://docs.nersc.gov/services/sfapi/" target="_blank" rel="noreferrer">Superfacility API</a> (SFAPI). All SFAPI logic lives in <code>backend/app/sfapi_runner.py</code>.</p><h2 id="submission-flow" tabindex="-1">Submission flow <a class="header-anchor" href="#submission-flow" aria-label="Permalink to &quot;Submission flow&quot;">​</a></h2><ol><li><p><strong>Estimate resources</strong> from the request parameters:</p><ul><li><code>target_per_task</code>: 50 events for ttbar, 100 for other channels</li><li><code>n_tasks = ceil(events / target_per_task)</code>, capped at 256</li><li><code>tasks_per_node = 32</code> (Perlmutter CPU: 128 cores, DDSim is memory-bound)</li><li><code>n_nodes = ceil(n_tasks / 32)</code>, capped at 8</li></ul></li><li><p><strong>Select queue</strong> based on estimated wall time:</p><table><thead><tr><th style="text-align:left;">Condition</th><th style="text-align:left;">QOS</th><th style="text-align:left;">Wall time</th></tr></thead><tbody><tr><td style="text-align:left;">est &lt; 25 min AND 1 node</td><td style="text-align:left;"><code>debug</code></td><td style="text-align:left;">30 min</td></tr><tr><td style="text-align:left;">est &lt; 2 h</td><td style="text-align:left;"><code>regular</code></td><td style="text-align:left;">2 h</td></tr><tr><td style="text-align:left;">otherwise</td><td style="text-align:left;"><code>regular</code></td><td style="text-align:left;">4 h</td></tr></tbody></table></li><li><p><strong>Render sbatch script</strong> from <code>backend/app/sbatch_template.sh.j2</code> (Jinja2).</p></li><li><p><strong>Upload script</strong> to Perlmutter scratch via SFAPI, then <code>submit_job()</code>.</p></li><li><p><strong>Record</strong> <code>nersc_jobid</code> and set state to <code>submitted</code>.</p></li></ol><h2 id="sbatch-template" tabindex="-1">Sbatch template <a class="header-anchor" href="#sbatch-template" aria-label="Permalink to &quot;Sbatch template&quot;">​</a></h2><p>Template variables: <code>request_id</code>, <code>channel</code>, <code>events</code>, <code>pileup</code>, <code>seed</code>, <code>project</code>, <code>qos</code>, <code>time_limit</code>, <code>n_nodes</code>, <code>tasks_per_node</code>, <code>events_per_task</code>, <code>work_dir</code>, <code>image</code>, <code>repo_branch</code>, <code>user_email</code>, <code>upload_to_hf</code>, <code>output_hf_repo</code>, <code>hf_token</code>.</p><h3 id="single-task-path" tabindex="-1">Single-task path <a class="header-anchor" href="#single-task-path" aria-label="Permalink to &quot;Single-task path&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shifter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash -c &quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  source /workspace/scripts/cli/setup_container_env.sh &amp;&amp;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  bash /workspace/scripts/cli/run_pipeline_docker.sh --channel {channel}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><h3 id="multi-node-multi-task-path" tabindex="-1">Multi-node / multi-task path <a class="header-anchor" href="#multi-node-multi-task-path" aria-label="Permalink to &quot;Multi-node / multi-task path&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">srun</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --exact</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shifter bash -c &#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  source /workspace/scripts/cli/setup_container_env.sh</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  TASK_ID=\${SLURM_PROCID:-0}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  export RUN_ID=$TASK_ID</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  export EVENTS={events_per_task}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  export SEED=$(({seed} + TASK_ID))</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  bash /workspace/scripts/cli/run_pipeline_docker.sh --channel {channel}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span></span></code></pre></div><p>Each SLURM task gets a unique <code>RUN_ID</code> and <code>SEED</code>, producing independent event batches that are merged after all tasks complete.</p><h3 id="work-directory-layout" tabindex="-1">Work directory layout <a class="header-anchor" href="#work-directory-layout" aria-label="Permalink to &quot;Work directory layout&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>/pscratch/sd/{u}/{nersc_user}/colliderml/{request_id}/</span></span>
<span class="line"><span>├── repo/              # shallow clone of colliderml-production@{branch}</span></span>
<span class="line"><span>├── runs/</span></span>
<span class="line"><span>│   ├── 0/             # task 0 output</span></span>
<span class="line"><span>│   ├── 1/             # task 1 output</span></span>
<span class="line"><span>│   └── …</span></span>
<span class="line"><span>└── merged/            # (if multi-task) combined output</span></span></code></pre></div><h3 id="output-upload" tabindex="-1">Output upload <a class="header-anchor" href="#output-upload" aria-label="Permalink to &quot;Output upload&quot;">​</a></h3><p>If <code>upload_to_hf=true</code> and <code>HF_TOKEN</code> is set, the sbatch epilogue creates a HuggingFace dataset repo <code>{HF_DATASET_ORG}/ColliderML-Service-{request_id}</code> and uploads all Parquet files from <code>runs/</code>.</p><h2 id="polling" tabindex="-1">Polling <a class="header-anchor" href="#polling" aria-label="Permalink to &quot;Polling&quot;">​</a></h2><p>A background <code>asyncio</code> task polls every <code>POLL_INTERVAL_SECONDS</code> (default 60):</p><ol><li>Call <code>job.update()</code> via SFAPI (run in a thread — the SFAPI client is synchronous)</li><li>Track state transitions</li><li>On terminal state → call <code>_finalise(request_id, user, slurm_state)</code></li></ol><p>Terminal SLURM states: <code>COMPLETED</code>, <code>FAILED</code>, <code>CANCELLED</code>, <code>TIMEOUT</code>, <code>NODE_FAIL</code>.</p><h3 id="finalisation" tabindex="-1">Finalisation <a class="header-anchor" href="#finalisation" aria-label="Permalink to &quot;Finalisation&quot;">​</a></h3><ul><li><strong>COMPLETED:</strong> mark state <code>completed</code>, set <code>output_hf_repo</code>, reconcile credits (refund overage if actual &lt; estimated)</li><li><strong>Other terminal state:</strong> mark state <code>failed</code>, record <code>error_message</code>, refund full charge</li></ul><h2 id="mock-mode" tabindex="-1">Mock mode <a class="header-anchor" href="#mock-mode" aria-label="Permalink to &quot;Mock mode&quot;">​</a></h2><p>When <code>SFAPI_CLIENT_ID</code> and <code>SFAPI_CLIENT_SECRET</code> are unset, the runner operates in <strong>mock mode</strong>:</p><ul><li>Logs <code>&quot;Mock submission for request {id}&quot;</code></li><li>Records <code>nersc_jobid = &quot;mock-0&quot;</code></li><li>Schedules a background task that sleeps 2 s, then calls <code>_finalise</code> with <code>COMPLETED</code></li></ul><p>This is the default for local development and staging deploys without NERSC credentials.</p><h2 id="sfapi-credentials" tabindex="-1">SFAPI credentials <a class="header-anchor" href="#sfapi-credentials" aria-label="Permalink to &quot;SFAPI credentials&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Env var</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>SFAPI_CLIENT_ID</code></td><td style="text-align:left;">NERSC IRIS OAuth2 client ID</td></tr><tr><td style="text-align:left;"><code>SFAPI_CLIENT_SECRET</code></td><td style="text-align:left;">PEM-encoded private key for the IRIS client</td></tr><tr><td style="text-align:left;"><code>NERSC_PROJECT</code></td><td style="text-align:left;">Allocation account (e.g., <code>m4958</code>)</td></tr><tr><td style="text-align:left;"><code>NERSC_USER</code></td><td style="text-align:left;">Service account username on Perlmutter</td></tr></tbody></table><p>Obtain credentials from <a href="https://iris.nersc.gov/" target="_blank" rel="noreferrer">iris.nersc.gov</a> under the project&#39;s API client management page.</p>`,28)]))}const k=t(i,[["render",o]]);export{u as __pageData,k as default};
